CREATE TABLE `cli_medications` (
  `ID` int NOT NULL AUTO_INCREMENT,
  `CODE` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Medication code',
  `PATIENT_ID` int NOT NULL COMMENT 'Reference to pat_patients',
  `VISIT_ID` int DEFAULT NULL COMMENT 'Reference to cli_visits',
  `FILE_ID` int DEFAULT NULL,
  `EMR_HEADER_ID` int DEFAULT NULL COMMENT 'Reference to cli_emr_headers',
  `MEDICATION_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Medication name',
  `GENERIC_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Generic name',
  `BRAND_NAME` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Brand name',
  `STRENGTH` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Strength/dosage',
  `FORM` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Form: TABLET, CAPSULE, INJECTION, etc.',
  `ROUTE` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Route: ORAL, IV, IM, TOPICAL, etc.',
  `FREQUENCY` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Frequency: BID, TID, Q8H, etc.',
  `DOSAGE` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Dosage instructions',
  `QUANTITY_PRESCRIBED` decimal(10,2) DEFAULT NULL COMMENT 'Quantity prescribed',
  `QUANTITY_DISPENSED` decimal(10,2) DEFAULT NULL COMMENT 'Quantity dispensed',
  `UNIT` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Unit: MG, ML, TABLETS, etc.',
  `REFILLS` int DEFAULT '0' COMMENT 'Number of refills',
  `REFILLS_REMAINING` int DEFAULT '0' COMMENT 'Refills remaining',
  `DAYS_SUPPLY` int DEFAULT NULL COMMENT 'Days supply',
  `START_DATE` date NOT NULL COMMENT 'Start date',
  `END_DATE` date DEFAULT NULL COMMENT 'End date',
  `PRESCRIBED_BY` int NOT NULL COMMENT 'Prescribed by provider',
  `PRESCRIPTION_DATE` datetime NOT NULL COMMENT 'Prescription date',
  `PHARMACY` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Dispensing pharmacy',
  `PRESCRIPTION_NUMBER` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Prescription number',
  `INDICATION` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Indication for use',
  `STATUS` int DEFAULT '1' COMMENT 'Status: 1=ACTIVE, 0=DISCONTINUED, 2=COMPLETED, 3=HOLD',
  `DISCONTINUATION_REASON` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Discontinuation reason',
  `DISCONTINUATION_DATE` datetime DEFAULT NULL COMMENT 'Discontinuation date',
  `ADVERSE_REACTIONS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Adverse reactions experienced',
  `EFFECTIVENESS_RATING` int DEFAULT NULL COMMENT 'Effectiveness rating (1-5)',
  `COMPLIANCE_RATING` int DEFAULT NULL COMMENT 'Compliance rating (1-5)',
  `COST` decimal(10,2) DEFAULT NULL COMMENT 'Medication cost',
  `INSURANCE_COVERAGE` decimal(10,2) DEFAULT NULL COMMENT 'Insurance coverage',
  `PATIENT_PAY` decimal(10,2) DEFAULT NULL COMMENT 'Patient payment amount',
  `LOT_NUMBER` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Medication lot number',
  `EXPIRATION_DATE` date DEFAULT NULL COMMENT 'Medication expiration date',
  `MANUFACTURER` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Manufacturer',
  `NDC_CODE` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'National Drug Code',
  `CONTROLLED_SUBSTANCE` tinyint(1) DEFAULT '0' COMMENT 'Is controlled substance',
  `CONTROLLED_SUBSTANCE_SCHEDULE` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Schedule: I, II, III, IV, V',
  `PRN` tinyint(1) DEFAULT '0' COMMENT 'As needed (PRN)',
  `PRN_REASONS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'PRN usage reasons',
  `MONITORING_PARAMETERS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Parameters to monitor',
  `INTERACTIONS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Drug interactions',
  `CONTRAINDICATIONS` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Contraindications',
  `NOTES` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT 'Medication notes',
  `CREATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `LAST_UPDATED_AT` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `STATUS_FLAG` int NOT NULL DEFAULT '1',
  `CREATED_BY` int DEFAULT NULL,
  `LAST_UPDATED_BY` int DEFAULT NULL,
  `LAST_UPDATED_PROGRAM` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`ID`),
  UNIQUE KEY `UK_CODE` (`CODE`),
  KEY `IDX_PATIENT_ID` (`PATIENT_ID`),
  KEY `IDX_VISIT_ID` (`VISIT_ID`),
  KEY `IDX_EMR_HEADER_ID` (`EMR_HEADER_ID`),
  KEY `IDX_MEDICATION_NAME` (`MEDICATION_NAME`),
  KEY `IDX_PRESCRIBED_BY` (`PRESCRIBED_BY`),
  KEY `IDX_PRESCRIPTION_DATE` (`PRESCRIPTION_DATE`),
  KEY `IDX_START_DATE` (`START_DATE`),
  KEY `IDX_END_DATE` (`END_DATE`),
  KEY `IDX_STATUS` (`STATUS`),
  KEY `IDX_CONTROLLED_SUBSTANCE` (`CONTROLLED_SUBSTANCE`),
  KEY `IDX_STATUS_FLAG` (`STATUS_FLAG`),
  KEY `IDX_CREATED_AT` (`CREATED_AT`),
  KEY `IDX_CLI_MEDICATIONS_PATIENT_ID` (`PATIENT_ID`),
  KEY `IDX_CLI_MEDICATIONS_PRESCRIBED_BY` (`PRESCRIBED_BY`),
  KEY `IDX_CLI_MEDICATIONS_START_DATE` (`START_DATE`),
  KEY `IDX_MEDICATION_FILE` (`FILE_ID`),
  CONSTRAINT `FK_MEDICATION_EMR_HEADER` FOREIGN KEY (`EMR_HEADER_ID`) REFERENCES `cli_emr_headers` (`ID`),
  CONSTRAINT `FK_MEDICATION_FILE` FOREIGN KEY (`FILE_ID`) REFERENCES `fil_files` (`ID`) ON DELETE CASCADE,
  CONSTRAINT `FK_MEDICATION_PATIENT` FOREIGN KEY (`PATIENT_ID`) REFERENCES `pat_patients` (`ID`),
  CONSTRAINT `FK_MEDICATION_PRESCRIBED_BY` FOREIGN KEY (`PRESCRIBED_BY`) REFERENCES `sta_doctors` (`ID`),
  CONSTRAINT `FK_MEDICATION_VISIT` FOREIGN KEY (`VISIT_ID`) REFERENCES `cli_visits` (`ID`)
) ENGINE=InnoDB AUTO_INCREMENT=2340 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Patient Medications';
